export const getCustList = (data: any[], selectField: any) => {
  let objValue: any = {};
  if (data.length > 0) {
    for (let i = 0; i < data.length; i++) {
      objValue[data[i][selectField]] = data[i].value;
    }
    return objValue;
  }
  else {
    return objValue;
  }
}
export function dynamicSort(property: any) {
  var sortOrder = 1;
  if (property[0] === "-") {
    sortOrder = -1;
    property = property.substr(1);
  }
  return function (a: any, b: any) {
    /* next line works with strings and numbers, 
     * and you may want to customize it to your needs
     */
    var result = (a[property] < b[property]) ? -1 : (a[property] > b[property]) ? 1 : 0;
    return result * sortOrder;
  }
}
export const treeCategoryToArray = (objesctArray: any, resutlArray: any) => {
  Array.isArray(objesctArray) && objesctArray.map((obj: any) => {
    if (!obj || obj?.categories || obj?.categories?.length <= 0) {
      obj.data = obj.products;
      resutlArray.push(obj);
    }
    resutlArray = treeCategoryToArray(obj?.categories, resutlArray);
  })
  return resutlArray;

};

